import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do annuity payouts work?", a: "Annuity payouts convert a lump sum into scheduled income over a chosen period. The payment depends on the starting balance, expected return, payout frequency, and number of years." },
  { q: "How do you calculate monthly annuity income?", a: "Monthly annuity income is calculated by spreading the lump sum across monthly payments while applying the expected monthly interest rate to the remaining balance." },
  { q: "What is a lifetime annuity?", a: "A lifetime annuity is designed to pay income for as long as the annuitant lives, instead of ending after a fixed number of years." },
  { q: "How does interest rate affect annuity payouts?", a: "A higher expected interest rate generally increases the payout amount because the remaining balance is assumed to keep earning income during the payout period." },
  { q: "What happens to an annuity when you die?", a: "It depends on the annuity contract. Some stop payments at death, while others include survivor benefits, refund features, or guaranteed payout periods." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(Number.isFinite(value) ? value : 0, { maximumFractionDigits: digits });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function payoutAmount(principal: number, annualRate: number, years: number, periodsPerYear = 12) {
  const n = Math.max(1, Math.round(years * periodsPerYear));
  const r = annualRate / 100 / periodsPerYear;
  if (r === 0) return principal / n;
  return principal * r / (1 - Math.pow(1 + r, -n));
}

export default function AnnuityPayoutCalculator() {
  useCurrencyVersion();
  const [lumpSum, setLumpSum] = useState(500000);
  const [rate, setRate] = useState(5);
  const [years, setYears] = useState(20);
  const [type, setType] = useState("monthly");
  const periods = type === "monthly" ? 12 : 1;

  const result = useMemo(() => {
    const payment = payoutAmount(lumpSum, rate, years, periods);
    let balance = lumpSum;
    const schedule = Array.from({ length: Math.min(Math.round(years * periods), 360) }, (_, i) => {
      const interest = balance * (rate / 100 / periods);
      const principal = Math.min(payment - interest, balance);
      balance = Math.max(0, balance + interest - payment);
      return { period: i + 1, interest, payout: payment, principal, balance };
    });
    return { payment, totalPaid: payment * years * periods, remaining: balance, schedule };
  }, [lumpSum, rate, years, periods]);

  const comparison = [3, 4, 5, 6, 7].map((r) => ({
    rate: r,
    y10: payoutAmount(500000, r, 10),
    y20: payoutAmount(500000, r, 20),
    y30: payoutAmount(500000, r, 30),
    lifetime: payoutAmount(500000, r, 25),
  }));

  return (
    <>
      <SEOHead title="Free Annuity Payout Calculator Online - Calculate Monthly Annuity Income Instantly | CalcHive" description="Free online annuity payout calculator. Calculate your monthly annuity income from any lump sum, interest rate and payout period instantly. 100% free, no signup required." canonical="/annuity-payout-calculator" keywords="free annuity payout calculator, monthly annuity income calculator free, annuity withdrawal calculator free online, calculate annuity payout free, retirement income calculator free" category="Financial Calculators" breadcrumbName="Free Annuity Payout Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Annuity Payout Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate monthly or annual annuity income from a lump sum, expected return, and payout period.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Lump sum amount</label><input type="number" value={lumpSum} onChange={(e) => setLumpSum(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Expected annual return (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Payout period in years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Payout type</label><select value={type} onChange={(e) => setType(e.target.value)} className={inputClass}><option value="monthly">Monthly</option><option value="annual">Annual</option></select></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{type === "monthly" ? "Monthly" : "Annual"} Payout</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.payment)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total paid out</p><p className="text-lg font-extrabold text-foreground">{money(result.totalPaid)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Remaining value</p><p className="text-lg font-extrabold text-foreground">{money(result.remaining)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Monthly Annuity Payouts for Free</h2><p className="text-muted-foreground leading-relaxed">This free annuity payout calculator estimates the payment that can be withdrawn each period from a starting balance while the remaining value earns interest.</p>
          <h2 className="text-2xl font-bold text-foreground">How Interest Rate and Payout Period Affect Your Income</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Monthly Payout From $500,000 Annuity at Different Rates</caption><thead className="bg-muted/60"><tr>{["Interest Rate", "10 Year Payout", "20 Year Payout", "30 Year Payout", "Lifetime (age 65-90)"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.rate}><td className="py-2.5 px-3 font-semibold">{row.rate}%</td><td className="py-2.5 px-3">{money(row.y10)}</td><td className="py-2.5 px-3">{money(row.y20)}</td><td className="py-2.5 px-3">{money(row.y30)}</td><td className="py-2.5 px-3">{money(row.lifetime)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Retirement Income Annuity Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Payout Schedule</caption><thead className="bg-muted/60"><tr>{["Period", "Payout", "Interest", "Principal", "Remaining Value"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.map((row) => <tr key={row.period}><td className="py-2.5 px-3">{row.period}</td><td className="py-2.5 px-3">{money(row.payout)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/annuity-payout-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


